// // This module implements a 3-bit binary down counter that decrements on every positive clock edge and resets to 7 when the reset signal is high.
module up_counter(
    input clk,
    input reset,
    output reg [2:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 3'd0;
        else
            count <= count + 1;
    end
endmodule
